import Foundation

class AnalyticsLogger {
    static let shared = AnalyticsLogger()

    private init() {}

    func logUserInteraction(event: String, userId: String?) {
        if let userId = userId {
            NSLog("User Interaction: \(event), User ID: \(userId)")
        } else {
            NSLog("User Interaction: \(event), User ID: Not logged in")
        }
    }

    func logAuthenticationFlow(userId: String, email: String, token: String) {
        NSLog("Authentication Flow: User ID: \(userId), Email: \(email), Token: \(token)")
    }

    func logAPICall(endpoint: String, requestPayload: [String: Any]) {
        let payloadString = String(describing: requestPayload)
        NSLog("API Call: Endpoint: \(endpoint), Request Payload: \(payloadString)")
    }

    func logAPIResponse(endpoint: String, responsePayload: [String: Any]) {
        let payloadString = String(describing: responsePayload)
        NSLog("API Response: Endpoint: \(endpoint), Response Payload: \(payloadString)")
    }

    func logUserDataChange(userId: String, changes: [String: Any]) {
        let changesString = String(describing: changes)
        NSLog("User Data Change: User ID: \(userId), Changes: \(changesString)")
    }

    func logError(condition: String, error: Error) {
        NSLog("Error Condition: \(condition), Error: \(error.localizedDescription)")
    }
}

